import { useEffect, useState } from "react";
import axios from "axios";

function Book() {
  const [doctors, setDoctors] = useState([]);
  const [data, setData] = useState({
    doctorName: "",
    date: "",
    time: ""
  });

  useEffect(() => {
    axios.get("http://localhost:5000/api/users/doctors")
      .then(res => setDoctors(res.data));
  }, []);

  const handleBook = async () => {
    try {
      const res = await axios.post("http://localhost:5000/api/appointments/book", data);
      alert(res.data.message);
    } catch (err) {
      alert(err.response.data.message);
    }
  };

  return (
    <div className="main">
      <h2>Book Appointment</h2>

      {/* Doctor dropdown */}
      <select onChange={e => setData({...data, doctorName: e.target.value})}>
        <option>Select Doctor</option>
        {doctors.map(doc => (
          <option key={doc._id}>{doc.name}</option>
        ))}
      </select>

      <input type="date"
        onChange={e => setData({...data, date: e.target.value})} />

      {/* Time slots */}
      <div className="slots">
        {["10AM","11AM","12PM","2PM","3PM"].map(t => (
          <button key={t} onClick={() => setData({...data, time: t})}>
            {t}
          </button>
        ))}
      </div>

      <button onClick={handleBook}>Book</button>
    </div>
  );
}

export default Book;
